package com.taskflow.entity;

import jakarta.validation.ConstraintViolation;
import jakarta.validation.Validation;
import jakarta.validation.Validator;
import jakarta.validation.ValidatorFactory;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;

class UserTest {

    private static Validator validator;

    @BeforeAll
    static void setUpValidator() {
        ValidatorFactory factory = Validation.buildDefaultValidatorFactory();
        validator = factory.getValidator();
    }

    @Test
    void shouldCreateUserWithAllFields() {
        User user = new User();
        user.setUsername("testuser");
        user.setPassword("hashedpassword");
        user.setDisplayName("Test User");

        assertEquals("testuser", user.getUsername());
        assertEquals("hashedpassword", user.getPassword());
        assertEquals("Test User", user.getDisplayName());
    }

    @Test
    void shouldHaveNullIdBeforePersistence() {
        User user = new User();
        assertNull(user.getId());
    }

    @Test
    void shouldHaveCreatedAtField() {
        User user = new User();
        // createdAt should be null before persistence, set by @PrePersist or similar
        assertNull(user.getCreatedAt());
    }

    // --- Username validation ---

    @Test
    void shouldRejectUsernameWithLessThan3Characters() {
        User user = new User();
        user.setUsername("ab");
        user.setPassword("validpass");
        user.setDisplayName("Valid Name");

        Set<ConstraintViolation<User>> violations = validator.validate(user);
        assertFalse(violations.isEmpty(), "Username with 2 chars should be rejected");
    }

    @Test
    void shouldAcceptUsernameWith3Characters() {
        User user = new User();
        user.setUsername("abc");
        user.setPassword("validpass");
        user.setDisplayName("Valid Name");

        Set<ConstraintViolation<User>> violations = validator.validate(user);
        boolean hasUsernameViolation = violations.stream()
                .anyMatch(v -> v.getPropertyPath().toString().equals("username"));
        assertFalse(hasUsernameViolation, "Username with 3 chars should be accepted");
    }

    @Test
    void shouldAcceptUsernameWith50Characters() {
        User user = new User();
        user.setUsername("a".repeat(50));
        user.setPassword("validpass");
        user.setDisplayName("Valid Name");

        Set<ConstraintViolation<User>> violations = validator.validate(user);
        boolean hasUsernameViolation = violations.stream()
                .anyMatch(v -> v.getPropertyPath().toString().equals("username"));
        assertFalse(hasUsernameViolation, "Username with 50 chars should be accepted");
    }

    @Test
    void shouldRejectUsernameWithMoreThan50Characters() {
        User user = new User();
        user.setUsername("a".repeat(51));
        user.setPassword("validpass");
        user.setDisplayName("Valid Name");

        Set<ConstraintViolation<User>> violations = validator.validate(user);
        assertFalse(violations.isEmpty(), "Username with 51 chars should be rejected");
    }

    @Test
    void shouldAcceptUsernameWithAlphanumericAndUnderscore() {
        User user = new User();
        user.setUsername("user_Name_123");
        user.setPassword("validpass");
        user.setDisplayName("Valid Name");

        Set<ConstraintViolation<User>> violations = validator.validate(user);
        boolean hasUsernameViolation = violations.stream()
                .anyMatch(v -> v.getPropertyPath().toString().equals("username"));
        assertFalse(hasUsernameViolation, "Alphanumeric + underscore username should be accepted");
    }

    @Test
    void shouldRejectUsernameWithSpecialCharacters() {
        User user = new User();
        user.setUsername("user@name!");
        user.setPassword("validpass");
        user.setDisplayName("Valid Name");

        Set<ConstraintViolation<User>> violations = validator.validate(user);
        assertFalse(violations.isEmpty(), "Username with special chars should be rejected");
    }

    // --- DisplayName validation ---

    @Test
    void shouldRejectEmptyDisplayName() {
        User user = new User();
        user.setUsername("validuser");
        user.setPassword("validpass");
        user.setDisplayName("");

        Set<ConstraintViolation<User>> violations = validator.validate(user);
        assertFalse(violations.isEmpty(), "Empty displayName should be rejected");
    }

    @Test
    void shouldRejectDisplayNameOver100Characters() {
        User user = new User();
        user.setUsername("validuser");
        user.setPassword("validpass");
        user.setDisplayName("a".repeat(101));

        Set<ConstraintViolation<User>> violations = validator.validate(user);
        assertFalse(violations.isEmpty(), "DisplayName with 101 chars should be rejected");
    }

    @Test
    void shouldAcceptDisplayNameWith100Characters() {
        User user = new User();
        user.setUsername("validuser");
        user.setPassword("validpass");
        user.setDisplayName("a".repeat(100));

        Set<ConstraintViolation<User>> violations = validator.validate(user);
        boolean hasDisplayNameViolation = violations.stream()
                .anyMatch(v -> v.getPropertyPath().toString().equals("displayName"));
        assertFalse(hasDisplayNameViolation, "DisplayName with 100 chars should be accepted");
    }
}

