package com.taskflow.security;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.*;

class JwtTokenProviderTest {

    private JwtTokenProvider jwtTokenProvider;

    // Must be at least 256 bits (32 bytes) for HMAC-SHA256
    private static final String TEST_SECRET = "this-is-a-test-secret-key-that-is-long-enough-for-hmac-sha256-algorithm";
    private static final long TEST_EXPIRATION = 86400000L; // 24 hours

    @BeforeEach
    void setUp() {
        jwtTokenProvider = new JwtTokenProvider();
        // Assume the provider has fields set via @Value or constructor
        // We'll set them via reflection or constructor — worker decides approach
        // For now, assume there are setter methods or a constructor
        jwtTokenProvider.setSecret(TEST_SECRET);
        jwtTokenProvider.setExpiration(TEST_EXPIRATION);
    }

    @Test
    void shouldGenerateNonNullToken() {
        String token = jwtTokenProvider.generateToken(1L);

        assertNotNull(token);
        assertFalse(token.isEmpty());
    }

    @Test
    void shouldGenerateValidToken() {
        String token = jwtTokenProvider.generateToken(1L);

        assertTrue(jwtTokenProvider.validateToken(token));
    }

    @Test
    void shouldExtractUserIdFromToken() {
        Long userId = 42L;
        String token = jwtTokenProvider.generateToken(userId);

        Long extractedId = jwtTokenProvider.getUserIdFromToken(token);

        assertEquals(userId, extractedId);
    }

    @Test
    void shouldReturnFalseForMalformedToken() {
        // M1-AC10: malformed token
        assertFalse(jwtTokenProvider.validateToken("not.a.valid.jwt"));
    }

    @Test
    void shouldReturnFalseForNullToken() {
        assertFalse(jwtTokenProvider.validateToken(null));
    }

    @Test
    void shouldReturnFalseForEmptyToken() {
        assertFalse(jwtTokenProvider.validateToken(""));
    }

    @Test
    void shouldReturnFalseForTokenWithWrongSignature() {
        String token = jwtTokenProvider.generateToken(1L);

        // Create another provider with different secret
        JwtTokenProvider otherProvider = new JwtTokenProvider();
        otherProvider.setSecret("a-completely-different-secret-key-for-testing-wrong-signatures");
        otherProvider.setExpiration(TEST_EXPIRATION);

        assertFalse(otherProvider.validateToken(token));
    }

    // M1-AC9: expired token
    @Test
    void shouldReturnFalseForExpiredToken() {
        // Create a provider with 0ms expiration (token expires immediately)
        JwtTokenProvider expiredProvider = new JwtTokenProvider();
        expiredProvider.setSecret(TEST_SECRET);
        expiredProvider.setExpiration(0L);

        String token = expiredProvider.generateToken(1L);

        // Token should be expired immediately (or within milliseconds)
        assertFalse(expiredProvider.validateToken(token));
    }

    @Test
    void shouldGenerateDifferentTokensForDifferentUsers() {
        String token1 = jwtTokenProvider.generateToken(1L);
        String token2 = jwtTokenProvider.generateToken(2L);

        assertNotEquals(token1, token2);
    }

    @Test
    void shouldExtractCorrectUserIdForMultipleTokens() {
        String token1 = jwtTokenProvider.generateToken(100L);
        String token2 = jwtTokenProvider.generateToken(200L);

        assertEquals(100L, jwtTokenProvider.getUserIdFromToken(token1));
        assertEquals(200L, jwtTokenProvider.getUserIdFromToken(token2));
    }
}

