package com.taskflow.security;

import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.AutoConfigureMockMvc;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.test.web.servlet.MockMvc;

import static org.junit.jupiter.api.Assertions.*;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.status;

@SpringBootTest
@AutoConfigureMockMvc
class SecurityIntegrationTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private PasswordEncoder passwordEncoder;

    @Autowired
    private JwtTokenProvider jwtTokenProvider;

    // Verify SecurityConfig: auth endpoints are public
    @Test
    void shouldAllowAccessToAuthEndpointsWithoutToken() throws Exception {
        // /api/auth/** should be permitted (even if endpoint doesn't exist yet, should not get 401)
        mockMvc.perform(get("/api/auth/me"))
                .andExpect(result -> {
                    int status = result.getResponse().getStatus();
                    // Should NOT be 403 (forbidden by security) — it could be 401 from filter logic
                    // or 404 if controller doesn't exist yet, but NOT 403 from SecurityConfig
                    assertNotEquals(403, status,
                            "Auth endpoints should not be blocked by security filter chain");
                });
    }

    // M1-AC8: no header -> 401 for protected endpoint
    @Test
    void shouldReturn401ForProtectedEndpointWithoutToken() throws Exception {
        mockMvc.perform(get("/api/tasks"))
                .andExpect(status().isUnauthorized());
    }

    // M1-AC9: expired token -> 401
    @Test
    void shouldReturn401ForProtectedEndpointWithExpiredToken() throws Exception {
        // Create a provider with 0 expiration to generate an expired token
        JwtTokenProvider expiredProvider = new JwtTokenProvider();
        expiredProvider.setSecret("this-is-a-test-secret-key-that-is-long-enough-for-hmac-sha256-algorithm");
        expiredProvider.setExpiration(0L);
        String expiredToken = expiredProvider.generateToken(1L);

        mockMvc.perform(get("/api/tasks")
                        .header("Authorization", "Bearer " + expiredToken))
                .andExpect(status().isUnauthorized());
    }

    // M1-AC10: malformed token -> 401
    @Test
    void shouldReturn401ForProtectedEndpointWithMalformedToken() throws Exception {
        mockMvc.perform(get("/api/tasks")
                        .header("Authorization", "Bearer not-a-valid-jwt"))
                .andExpect(status().isUnauthorized());
    }

    // Verify SecurityConfig has BCryptPasswordEncoder bean
    @Test
    void shouldHaveBCryptPasswordEncoderBean() {
        assertNotNull(passwordEncoder);
        assertTrue(passwordEncoder instanceof org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder);
    }

    // M1-AC3: bcrypt encoding works correctly
    @Test
    void shouldEncodeToBcryptHash() {
        String rawPassword = "testpassword";
        String encoded = passwordEncoder.encode(rawPassword);

        assertTrue(encoded.startsWith("$2a$") || encoded.startsWith("$2b$"),
                "Encoded password should be bcrypt format");
        assertTrue(passwordEncoder.matches(rawPassword, encoded),
                "Password should match after encoding");
        assertNotEquals(rawPassword, encoded,
                "Encoded password should not equal raw password");
    }

    // Verify h2-console is accessible
    @Test
    void shouldAllowAccessToH2Console() throws Exception {
        mockMvc.perform(get("/h2-console/"))
                .andExpect(result -> {
                    int status = result.getResponse().getStatus();
                    assertNotEquals(401, status, "H2 console should not require auth");
                    assertNotEquals(403, status, "H2 console should not be forbidden");
                });
    }

    // Valid token should allow access to protected endpoint
    @Test
    void shouldAllowAccessToProtectedEndpointWithValidToken() throws Exception {
        String token = jwtTokenProvider.generateToken(1L);

        mockMvc.perform(get("/api/tasks")
                        .header("Authorization", "Bearer " + token))
                .andExpect(result -> {
                    int status = result.getResponse().getStatus();
                    // Should NOT be 401 or 403 — might be 404 if TaskController doesn't exist
                    assertNotEquals(401, status, "Valid token should not get 401");
                    assertNotEquals(403, status, "Valid token should not get 403");
                });
    }
}

